-- Tabela Principal: Controle de Processos de Clientes
CREATE TABLE public.controle_processos_clientes (
    id UUID DEFAULT auth.uid() PRIMARY KEY, -- Você pode usar uuid_generate_v4() se a extensão uuid-ossp estiver ativa
    quadra TEXT,
    lote TEXT,
    corretor TEXT,
    nome_cliente TEXT,
    data_simulacao DATE,
    data_aprovacao DATE,
    validade DATE,
    situacao TEXT,
    valor_imovel NUMERIC(15,2),
    entrada NUMERIC(15,2),
    numero_imovel TEXT,
    telefone_cliente TEXT,
    observacao TEXT,
    data_cadastro_sistema TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Tabela de Logs de Auditoria
CREATE TABLE public.logs_controle_clientes (
    id_log UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    processo_id UUID REFERENCES public.controle_processos_clientes(id) ON DELETE CASCADE,
    acao TEXT NOT NULL CHECK (acao IN ('CRIADO', 'ALTERADO', 'EXCLUIDO')),
    detalhes_alteracao JSONB, -- Usando JSONB para facilitar armazenar os campos "De -> Para"
    data_hora_alteracao TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Alterando tipo do id na tabela principal caso queira UUID automático e não use auth.uid()
ALTER TABLE public.controle_processos_clientes ALTER COLUMN id SET DEFAULT gen_random_uuid();

